	SELECT SEQ_DDD_ARCHIVE.NEXTVAL FROM DUAL

INSERT INTO DDD_ARCHIVE (
	DOG_NUMBER, USER_NUMBER, DOG_NAME, DOG_BREED, DOG_GENDER,
	DOG_AGE, DOG_WEIGHT, DOG_SAFE_DATE, DOG_ARCHIVE_DATE, DOG_DETAIL
) VALUES (
	#{dogNumber}, #{userNumber}, #{dogName}, #{dogBreed}, #{dogGender},
	#{dogAge}, #{dogWeight}, 
	TO_DATE(REPLACE(SUBSTR(#{dogSafeDate}, 1, 10), 'T', ''), 'YYYY-MM-DD'),
	SYSDATE, #{dogDetail}
)

INSERT INTO DDD_ARCHIVE_SCORE (
	DOG_NUMBER, DOG_ACTIVITY, DOG_SOCIALITY, DOG_INDEPENDENCE, DOG_BARKING, DOG_GROOMING,
	DOG_ACTIVITY_DETAIL, DOG_SOCIALITY_DETAIL, DOG_INDEPENDENCE_DETAIL, DOG_BARKING_DETAIL, DOG_GROOMING_DETAIL
) VALUES ( 
	#{dogNumber}, #{dogActivity}, #{dogSociality}, #{dogIndependence}, #{dogBarking}, #{dogGrooming},
	#{dogActivityDetail}, #{dogSocialityDetail}, #{dogIndependenceDetail}, #{dogBarkingDetail}, #{dogGroomingDetail}
)

